sql:
SELECT SUM(total_amount) AS total_claimed_amount
FROM travel_reports
WHERE report_type = 'daily' AND status = 'approved';

external_knowledge:
- 'big-ticket travel expenses' refers to those with a total amount greater than 5000; 
- 'top-level manager' refers to the manager with ID 3; 
- 'fully compliant with the company's travel policy' means the report's compliant field (pc.compliant) is 1.

sql:
SELECT employee_id, SUM(balance_change) AS total_balance_change
FROM balance_history
GROUP BY employee_id;

SELECT employee_id, date, start_location_id
FROM journeys
LIMIT 3;

SELECT *
FROM journeys
WHERE distance > (
    SELECT AVG(distance) 
    FROM journeys
);
